import {ChangeDetectionStrategy, ChangeDetectorRef, Component, OnInit} from '@angular/core';

declare var data : any;

@Component({
    selector: 'app-quote',
    templateUrl: './quote.component.html',
    changeDetection: ChangeDetectionStrategy.OnPush,
    styleUrls: ['./quote.component.css'],
    standalone: false
})
export class QuoteComponent implements OnInit {
	public quoteData = this.getRandomValue(data['Quote']);
	constructor(private changeDetectorRef: ChangeDetectorRef) {
		changeDetectorRef.detach();
	}

	public getRandomValue(e : any) {
		return Array.isArray(e) ? e[Math.floor(Math.random() * e.length)] : e;
	}

	ngOnInit(): void {
		this.changeDetectorRef.detectChanges();
	}
}
<section class="quote-section"><div class=overlay></div><div class=container><div class="row justify-content-center"><blockquote class="col-md-7 text-center fadeInUp"><h3 class="wow slideInLeft h2 mb-5" data-wow-duration=0.25s data-wow-delay=0.1s>“{{quoteData['quote']}}”</h3><h4 class="wow slideInRight h2" data-wow-duration=0.25s data-wow-delay=0.1s><cite title="{{quoteData['author']}}">- {{quoteData['author']}}</cite></h4></blockquote></div></div></section>
